package com.smithware.lastdone.data
import org.json.*

data class LastDoneBackup(val categories:List<Category>,val items:List<TrackedItem>,val completions:List<CompletionRecord>)
object BackupCodec{
 const val FORMAT_VERSION=1
 fun encode(value:LastDoneBackup):String=JSONObject().put("format","com.smithware.lastdone.backup").put("version",FORMAT_VERSION).put("categories",JSONArray(value.categories.map{JSONObject().put("id",it.id).put("name",it.name).put("icon",it.icon).put("color",it.color).put("builtIn",it.builtIn).put("hidden",it.hidden)})).put("items",JSONArray(value.items.map{JSONObject().put("id",it.id).put("name",it.name).put("description",it.description).put("categoryId",it.categoryId).put("icon",it.icon).put("expectedDays",it.expectedDays?:JSONObject.NULL).put("reminderEnabled",it.reminderEnabled).put("notes",it.notes).put("location",it.location).put("person",it.associatedPerson).put("vehicle",it.associatedVehicle).put("pet",it.associatedPet).put("estimatedCostCents",it.estimatedCostCents?:JSONObject.NULL).put("archived",it.archived).put("createdAt",it.createdAt)})).put("completions",JSONArray(value.completions.map{JSONObject().put("id",it.id).put("itemId",it.itemId).put("completedAt",it.completedAt).put("note",it.note).put("costCents",it.costCents?:JSONObject.NULL).put("measurement",it.measurement).put("location",it.location).put("person",it.person).put("serviceProvider",it.serviceProvider).put("customDetails",it.customDetails)})).toString(2)
 fun decode(text:String):LastDoneBackup{val root=JSONObject(text);require(root.optString("format")=="com.smithware.lastdone.backup"){"This is not a LastDone backup"};require(root.optInt("version",-1)==FORMAT_VERSION){"Unsupported backup version"};val categories=root.getJSONArray("categories").objects().map{Category(id=it.getLong("id"),name=it.getString("name"),icon=it.optString("icon","●"),color=it.optLong("color",0xFF637B52),builtIn=it.optBoolean("builtIn"),hidden=it.optBoolean("hidden"))};val categoryIds=categories.map{it.id}.toSet();val items=root.getJSONArray("items").objects().map{TrackedItem(id=it.getLong("id"),name=it.getString("name"),description=it.optString("description"),categoryId=it.getLong("categoryId"),icon=it.optString("icon","✓"),expectedDays=it.nullableInt("expectedDays"),reminderEnabled=it.optBoolean("reminderEnabled"),notes=it.optString("notes"),location=it.optString("location"),associatedPerson=it.optString("person"),associatedVehicle=it.optString("vehicle"),associatedPet=it.optString("pet"),estimatedCostCents=it.nullableLong("estimatedCostCents"),archived=it.optBoolean("archived"),createdAt=it.optLong("createdAt",System.currentTimeMillis()))};require(items.all{it.name.isNotBlank()&&it.categoryId in categoryIds}){"Backup contains an invalid item or category link"};val itemIds=items.map{it.id}.toSet();val completions=root.getJSONArray("completions").objects().map{CompletionRecord(id=it.getLong("id"),itemId=it.getLong("itemId"),completedAt=it.getLong("completedAt"),note=it.optString("note"),costCents=it.nullableLong("costCents"),measurement=it.optString("measurement"),location=it.optString("location"),person=it.optString("person"),serviceProvider=it.optString("serviceProvider"),customDetails=it.optString("customDetails"))};require(completions.all{it.itemId in itemIds&&it.completedAt<=System.currentTimeMillis()+60_000}){"Backup contains invalid or future completion history"};return LastDoneBackup(categories,items,completions)}
 private fun JSONArray.objects()=List(length()){getJSONObject(it)}
 private fun JSONObject.nullableLong(key:String)=if(isNull(key))null else getLong(key)
 private fun JSONObject.nullableInt(key:String)=if(isNull(key))null else getInt(key)
}
